INSERT INTO _import_item_trait_data (trait_name, description, activation_scope) VALUES
    ('Item: +1 Ammunition', '[Uncommon] You have a +1 bonus to attack and damage rolls made with this piece of magic ammunition. Once it hits a target, the ammunition is no longer magical. This ammunition is typically found or sold in quantities of ten or twenty pieces. Ten pieces of this ammunition are equivalent in value to a potion of the same rarity <i class="ve-muted">(200 GP)</i>.', 'equipped'),
    ('Item: +1 Armor', '[Rare] You have a +1 bonus to AC while wearing this armor.', 'equipped'),
    ('Item: +1 Rod of the Pact Keeper', '[Uncommon] While holding this rod, you gain a +1 bonus to spell attack rolls and to the saving throw DCs of your Warlock spells. In addition, you can regain one spell slot as a Magic action while holding the rod. You can''t use this property again until you finish a Long Rest.', 'equipped'),
    ('Item: +1 Shield (*)', '[Uncommon] While holding this Shield, you have a +1 bonus to Armor Class, in addition to the Shield''s normal bonus to AC.', 'equipped'),
    ('Item: +1 Wand of the War Mage', '[Uncommon] While holding this wand, you gain a +1 bonus to spell attack rolls. In addition, you ignore Half Cover when making a spell attack roll.', 'equipped'),
    ('Item: +1 Weapon', '[Uncommon] You have a +1 bonus to attack and damage rolls made with this magic weapon.', 'equipped'),
    ('Item: +1 Wraps of Unarmed Power', '[Uncommon] While wearing these wraps, you have a +1 bonus to attack rolls and damage rolls made with your Unarmed Strikes. Those strikes deal your choice of Force damage or their normal damage type.', 'equipped'),
    ('Item: +2 Ammunition', '[Rare] You have a +2 bonus to attack and damage rolls made with this piece of magic ammunition. Once it hits a target, the ammunition is no longer magical. This ammunition is typically found or sold in quantities of ten or twenty pieces. Ten pieces of this ammunition are equivalent in value to a potion of the same rarity <i class="ve-muted">(2,000 GP)</i>.', 'equipped'),
    ('Item: +2 Armor', '[Very Rare] You have a +2 bonus to AC while wearing this armor.', 'equipped'),
    ('Item: +2 Rod of the Pact Keeper', '[Rare] While holding this rod, you gain a +2 bonus to spell attack rolls and to the saving throw DCs of your Warlock spells. In addition, you can regain one spell slot as a Magic action while holding the rod. You can''t use this property again until you finish a Long Rest.', 'equipped'),
    ('Item: +2 Shield (*)', '[Rare] While holding this Shield, you have a +2 bonus to Armor Class, in addition to the Shield''s normal bonus to AC.', 'equipped'),
    ('Item: +2 Wand of the War Mage', '[Rare] While holding this wand, you gain a +2 bonus to spell attack rolls. In addition, you ignore Half Cover when making a spell attack roll.', 'equipped'),
    ('Item: +2 Weapon', '[Rare] You have a +2 bonus to attack and damage rolls made with this magic weapon.', 'equipped'),
    ('Item: +2 Wraps of Unarmed Power', '[Rare] While wearing these wraps, you have a +2 bonus to attack rolls and damage rolls made with your Unarmed Strikes. Those strikes deal your choice of Force damage or their normal damage type.', 'equipped'),
    ('Item: +3 Ammunition', '[Very Rare] You have a +3 bonus to attack and damage rolls made with this piece of magic ammunition. Once it hits a target, the ammunition is no longer magical. This ammunition is typically found or sold in quantities of ten or twenty pieces. Ten pieces of this ammunition are equivalent in value to a potion of the same rarity <i class="ve-muted">(20,000 GP)</i>.', 'equipped'),
    ('Item: +3 Armor', '[Legendary] You have a +3 bonus to AC while wearing this armor.', 'equipped'),
    ('Item: +3 Rod of the Pact Keeper', '[Very Rare] While holding this rod, you gain a +3 bonus to spell attack rolls and to the saving throw DCs of your Warlock spells. In addition, you can regain one spell slot as a Magic action while holding the rod. You can''t use this property again until you finish a Long Rest.', 'equipped'),
    ('Item: +3 Shield (*)', '[Very Rare] While holding this Shield, you have a +3 bonus to Armor Class, in addition to the Shield''s normal bonus to AC.', 'equipped'),
    ('Item: +3 Wand of the War Mage', '[Very Rare] While holding this wand, you gain a +3 bonus to spell attack rolls. In addition, you ignore Half Cover when making a spell attack roll.', 'equipped'),
    ('Item: +3 Weapon', '[Very Rare] You have a +3 bonus to attack and damage rolls made with this magic weapon.', 'equipped'),
    ('Item: +3 Wraps of Unarmed Power', '[Very Rare] While wearing these wraps, you have a +3 bonus to attack rolls and damage rolls made with your Unarmed Strikes. Those strikes deal your choice of Force damage or their normal damage type.', 'equipped'),
    ('Item: Adamantine Armor', '[Uncommon] This suit of armor is reinforced with adamantine, one of the hardest substances in existence. While you''re wearing it, any Critical Hit against you becomes a normal hit.', 'equipped'),
    ('Item: Adamantine Weapon', '[Uncommon] This weapon or piece of ammunition is made of adamantine, one of the hardest substances in existence. Whenever this weapon or piece of ammunition hits an object, the hit is a Critical Hit.', 'equipped'),
    ('Item: Alchemy Jug', '[Uncommon] This ceramic jug appears to be able to hold a gallon of liquid and weighs 12 pounds whether full or empty. The jug sloshes when it is shaken, even if the jug is empty. You can take a Magic action and name one liquid from the Alchemy Jug Liquids table to cause the jug to produce the chosen liquid. Afterward, you can uncork the jug as a Utilize action and pour that liquid out, up to 2 gallons per minute. The maximum amount of liquid the jug can produce depends on the liquid you named.', 'equipped'),
    ('Item: Ammunition of Slaying', '[Very Rare] This magic ammunition is meant to slay creatures of a particular type, which the DM chooses or determines randomly by rolling on the table below. If a creature of that type takes damage from the ammunition, the creature makes a DC 17 Constitution saving throw, taking an extra 6d10 Force damage on a failed save or half as much extra damage on a successful one. After dealing its extra damage to a creature, the ammunition becomes nonmagical.', 'equipped'),
    ('Item: Amulet of Health', '[Rare] Your Constitution score is 19 while you wear this amulet. It has no effect on you if your Constitution is already 19 or higher without it.', 'equipped'),
    ('Item: Amulet of Proof against Detection and Location', '[Uncommon] While wearing this amulet, you can''t be targeted by Divination spells or perceived through magical scrying sensors unless you allow it.', 'equipped'),
    ('Item: Amulet of the Planes', '[Very Rare] While wearing this amulet, you can take a Magic action to name a location that you are familiar with on another plane of existence. Then make a DC 15 Intelligence (Arcana) check. On a successful check, you cast Plane Shift. On a failed check, you and each creature and object within 15 feet of you travel to a random destination determined by rolling 1d100 and consulting the following table. 1d100｜Destination', 'equipped'),
    ('Item: Animated Shield', '[Very Rare] While holding this Shield, you can take a Bonus Action to cause it to animate. The Shield leaps into the air and hovers in your space to protect you as if you were wielding it, leaving your hands free. The Shield remains animate for 1 minute, until you take a Bonus Action to end this effect, or until you die or have the Incapacitated condition, at which point the Shield falls to the ground or into your hand if you have one free.', 'equipped'),
    ('Item: Apparatus of Kwalish', '[Legendary] This item first appears to be a sealed iron barrel weighing 500 pounds. The barrel has a hidden catch, which can be found with a successful DC 20 Intelligence (Investigation) check. Releasing the catch unlocks a hatch at one end of the barrel, allowing two Medium or smaller creatures to crawl inside. Ten levers are set in a row at the far end, each in a neutral position, able to move up or down. When certain levers are used, the apparatus transforms to resemble a giant lobster. The Apparatus of Kwalish is a Large object with the following statistics: <b>AC</b> 20; <b>HP</b> 200;...', 'equipped'),
    ('Item: Armor of Acid Resistance', '[Rare] You have Resistance to Acid damage while you wear this armor.', 'equipped'),
    ('Item: Armor of Cold Resistance', '[Rare] You have Resistance to Cold damage while you wear this armor.', 'equipped'),
    ('Item: Armor of Fire Resistance', '[Rare] You have Resistance to Fire damage while you wear this armor.', 'equipped'),
    ('Item: Armor of Force Resistance', '[Rare] You have Resistance to Force damage while you wear this armor.', 'equipped'),
    ('Item: Armor of Gleaming', '[Common] This armor never gets dirty.', 'equipped'),
    ('Item: Armor of Invulnerability', '[Legendary] You have Resistance to Bludgeoning, Piercing, and Slashing damage while you wear this armor. You can take a Magic action to give yourself Immunity to Bludgeoning, Piercing, and Slashing damage for 10 minutes or until you are no longer wearing the armor. Once this property is used, it can''t be used again until the next dawn.', 'equipped'),
    ('Item: Armor of Lightning Resistance', '[Rare] You have Resistance to Lightning damage while you wear this armor.', 'equipped'),
    ('Item: Armor of Necrotic Resistance', '[Rare] You have Resistance to Necrotic damage while you wear this armor.', 'equipped'),
    ('Item: Armor of Poison Resistance', '[Rare] You have Resistance to Poison damage while you wear this armor.', 'equipped'),
    ('Item: Armor of Psychic Resistance', '[Rare] You have Resistance to Psychic damage while you wear this armor.', 'equipped'),
    ('Item: Armor of Radiant Resistance', '[Rare] You have Resistance to Radiant damage while you wear this armor.', 'equipped'),
    ('Item: Armor of Resistance', '[Rare] You have Resistance to one type of damage while you wear this armor. The DM chooses the type or determines it randomly by rolling on the following table. d10｜Damage Type', 'equipped'),
    ('Item: Armor of Thunder Resistance', '[Rare] You have Resistance to Thunder damage while you wear this armor.', 'equipped'),
    ('Item: Armor of Vulnerability', '[Rare] Generic Variant, Rare (Requires Attunement)', 'equipped'),
    ('Item: Armor of Vulnerability (Bludgeoning)', '[Rare] While wearing this armor, you have Resistance to Bludgeoning damage. This armor is cursed, a fact that is revealed only when the Identify spell is cast on the armor or you attune to it. Attuning to the armor curses you until you are targeted by a Remove Curse spell or similar magic; removing the armor fails to end the curse. While cursed, you have Vulnerability to Piercing and Slashing damage.', 'equipped'),
    ('Item: Armor of Vulnerability (Piercing)', '[Rare] While wearing this armor, you have Resistance to Piercing damage. This armor is cursed, a fact that is revealed only when the Identify spell is cast on the armor or you attune to it. Attuning to the armor curses you until you are targeted by a Remove Curse spell or similar magic; removing the armor fails to end the curse. While cursed, you have Vulnerability to Bludgeoning and Slashing damage.', 'equipped'),
    ('Item: Armor of Vulnerability (Slashing)', '[Rare] While wearing this armor, you have Resistance to Slashing damage. This armor is cursed, a fact that is revealed only when the Identify spell is cast on the armor or you attune to it. Attuning to the armor curses you until you are targeted by a Remove Curse spell or similar magic; removing the armor fails to end the curse. While cursed, you have Vulnerability to Bludgeoning and Piercing damage.', 'equipped'),
    ('Item: Arrow-Catching Shield', '[Rare] You gain a +2 bonus to Armor Class against ranged attack rolls while you wield this Shield. This bonus is in addition to the Shield''s normal bonus to AC. Whenever an attacker makes a ranged attack roll against a target within 5 feet of you, you can take a Reaction to become the target of the attack instead.', 'equipped'),
    ('Item: Axe of the Dwarvish Lords', '[Artifact] A young dwarf prince set out to forge a weapon that would be regarded as a symbol of unity among his people. Venturing deep under the mountains, deeper than any dwarf had ever delved, the prince came to the blazing heart of a great volcano. With the aid of Moradin, a god of creation, he first crafted four mighty tools: the Starmetal Pick, the Earthheart Forge, the Anvil of Songs, and the Shaping Hammer. With these tools, he forged the Axe of the Dwarvish Lords. Armed with the Artifact, the prince brought peace to the dwarf clans, ending grudges and answering slights. The clans be...', 'equipped'),
    ('Item: Baba Yaga''s Dancing Broom', '[Uncommon] The archfey Baba Yaga crafted many of these magic brooms. No two appear exactly alike. While holding the broom, you can take a Magic action to transform it into an Animated Broom under your control. The broom then moves into an unoccupied space as close to you as possible. The broom acts immediately after you on your Initiative count and remains animate until you take a Bonus Action and use a command word to render it inanimate. On your turn, you can mentally command the animated broom if it is within 30 feet of you and you don''t have the Incapacitated condition (no action requir...', 'equipped'),
    ('Item: Bag of Beans', '[Rare] This heavy cloth bag contains 3d4 dry beans when found. The bag weighs half a pound regardless of how many beans it contains and becomes a nonmagical item when it no longer contains any beans. If you dump one or more beans out of the bag, they explode in a 10-foot-radius Sphere centered on them. All the dumped beans are destroyed in the explosion, and each creature in the Sphere, including you, makes a DC 15 Dexterity saving throw, taking 5d4 Force damage on a failed save or half as much damage on a successful one.', 'equipped'),
    ('Item: Bag of Devouring', '[Very Rare] This bag resembles a Bag of Holding but is a feeding orifice for a gigantic extradimensional creature. Turning the bag inside out closes the orifice. The extradimensional creature attached to the bag can sense whatever is placed inside the bag. Animal or vegetable matter placed wholly in the bag is devoured and lost forever. When part of a living creature is placed in the bag, as happens when someone reaches inside it, there is a 50 percent chance that the creature is pulled inside the bag. A creature inside the bag can take an action to try to escape, doing so with a successful...', 'equipped'),
    ('Item: Bag of Holding', '[Uncommon] This bag has an interior space considerably larger than its outside dimensions—roughly 2 feet square and 4 feet deep on the inside. The bag can hold up to 500 pounds, not exceeding a volume of 64 cubic feet. The bag weighs 5 pounds, regardless of its contents. Retrieving an item from the bag requires a Utilize action. If the bag is overloaded, pierced, or torn, it is destroyed, and its contents are scattered in the Astral Plane. If the bag is turned inside out, its contents spill forth unharmed, but the bag must be put right before it can be used again. The bag holds enough air f...', 'equipped'),
    ('Item: Bag of Tricks', '[Uncommon] Wondrous Item, Uncommon', 'equipped'),
    ('Item: Bag of Tricks, Gray', '[Uncommon] This bag made from gray cloth appears empty. Reaching inside the bag, however, reveals the presence of a small, fuzzy object. You can take a Magic action to pull the fuzzy object from the bag and throw it up to 20 feet. When the object lands, it transforms into a creature you determine by rolling on the table below. See the Monster Manual for the creature''s stat block. The creature vanishes at the next dawn or when it is reduced to 0 Hit Points.', 'equipped'),
    ('Item: Bag of Tricks, Rust', '[Uncommon] This bag made from rust cloth appears empty. Reaching inside the bag, however, reveals the presence of a small, fuzzy object. You can take a Magic action to pull the fuzzy object from the bag and throw it up to 20 feet. When the object lands, it transforms into a creature you determine by rolling on the table below. See the Monster Manual for the creature''s stat block. The creature vanishes at the next dawn or when it is reduced to 0 Hit Points.', 'equipped'),
    ('Item: Bag of Tricks, Tan', '[Uncommon] This bag made from tan cloth appears empty. Reaching inside the bag, however, reveals the presence of a small, fuzzy object. You can take a Magic action to pull the fuzzy object from the bag and throw it up to 20 feet. When the object lands, it transforms into a creature you determine by rolling on the table below. See the Monster Manual for the creature''s stat block. The creature vanishes at the next dawn or when it is reduced to 0 Hit Points.', 'equipped'),
    ('Item: Bead of Force', '[Rare] This small black sphere measures 3/4 of an inch in diameter and weighs an ounce. Typically, 1d4 + 4 Beads of Force are found together. You can take a Magic action to throw the bead up to 60 feet. The bead explodes in a 10-foot-radius Sphere on impact and is destroyed. Each creature in the Sphere must succeed on a DC 15 Dexterity saving throw or take 5d4 Force damage. A sphere of transparent force then encloses the area for 1 minute. Any creature that failed the save and is completely within the area is trapped inside this sphere. Creatures that succeeded on the save or are partially ...', 'equipped'),
    ('Item: Bead of Nourishment', '[Common] This flavorless, gelatinous bead dissolves on your tongue and provides as much nourishment as 1 day of Rations.', 'equipped'),
    ('Item: Bead of Refreshment', '[Common] This flavorless, gelatinous bead dissolves in liquid, transforming up to a pint of the liquid into fresh, cold drinking water. The bead has no effect on magical liquids or harmful substances such as poison.', 'equipped'),
    ('Item: Belt of Cloud Giant Strength', '[Legendary] While wearing this belt, your Strength score changes to 27. The item has no effect on you if your Strength without the belt is equal to or greater than the belt''s score.', 'equipped'),
    ('Item: Belt of Dwarvenkind', '[Rare] While wearing this belt, you gain the following benefits: In addition, while attuned to the belt, you have a 50 percent chance each day at dawn of growing a full beard if you can grow one, or a thicker beard if you already have one.', 'equipped'),
    ('Item: Belt of Fire Giant Strength', '[Very Rare] While wearing this belt, your Strength score changes to 25. The item has no effect on you if your Strength without the belt is equal to or greater than the belt''s score.', 'equipped'),
    ('Item: Belt of Frost Giant Strength', '[Very Rare] While wearing this belt, your Strength score changes to 23. The item has no effect on you if your Strength without the belt is equal to or greater than the belt''s score.', 'equipped'),
    ('Item: Belt of Giant Strength', 'Belt｜Str.｜Rarity Belt of Hill Giant Strength｜21｜Rare', 'equipped'),
    ('Item: Belt of Hill Giant Strength', '[Rare] While wearing this belt, your Strength score changes to 21. The item has no effect on you if your Strength without the belt is equal to or greater than the belt''s score.', 'equipped'),
    ('Item: Belt of Stone Giant Strength', '[Very Rare] While wearing this belt, your Strength score changes to 23. The item has no effect on you if your Strength without the belt is equal to or greater than the belt''s score.', 'equipped'),
    ('Item: Belt of Storm Giant Strength', '[Legendary] While wearing this belt, your Strength score changes to 29. The item has no effect on you if your Strength without the belt is equal to or greater than the belt''s score.', 'equipped'),
    ('Item: Berserker Axe', '[Rare] You gain a +1 bonus to attack rolls and damage rolls made with this magic weapon. In addition, while you are attuned to this weapon, your Hit Point maximum increases by 1 for each level you have attained. This weapon is cursed, and becoming attuned to it extends the curse to you. As long as you remain cursed, you are unwilling to part with the weapon, keeping it within reach at all times. You also have Disadvantage on attack rolls with weapons other than this one.', 'equipped'),
    ('Item: Black Dragon Scale Mail', '[Very Rare] Dragon Scale Mail is made of the scales of one kind of dragon. Sometimes dragons collect their cast-off scales and gift them. Other times, hunters carefully preserve the hide of a dead dragon. In either case, Dragon Scale Mail is highly valued. While wearing this armor, you gain a +1 bonus to Armor Class, you have Advantage on saving throws against the breath weapons of Dragons, and you have Resistance to Acid damage.', 'equipped'),
    ('Item: Blackrazor', '[Artifact] Hidden in the dungeon of White Plume Mountain, Blackrazor shines like a piece of night sky filled with stars. Its black scabbard is decorated with pieces of cut obsidian. You gain a +3 bonus to attack rolls and damage rolls made with this magic weapon. If you hit an Undead with this weapon, you take 1d10 Necrotic damage, and the target regains 1d10 Hit Points. If this Necrotic damage reduces you to 0 Hit Points, Blackrazor devours your soul (see "Devour Soul" below).', 'equipped'),
    ('Item: Blue Dragon Scale Mail', '[Very Rare] Dragon Scale Mail is made of the scales of one kind of dragon. Sometimes dragons collect their cast-off scales and gift them. Other times, hunters carefully preserve the hide of a dead dragon. In either case, Dragon Scale Mail is highly valued. While wearing this armor, you gain a +1 bonus to Armor Class, you have Advantage on saving throws against the breath weapons of Dragons, and you have Resistance to Lightning damage.', 'equipped'),
    ('Item: Book of Exalted Deeds', '[Artifact] The definitive treatise on all that is good in the multiverse, the Book of Exalted Deeds figures prominently in many religions. Rather than being a scripture devoted to a particular faith, the book''s authors filled the pages with their own visions of true virtue, providing guidance for defeating evil. The Book of Exalted Deeds rarely lingers in one place. As soon as the book is read, it vanishes to some other corner of the multiverse where its moral guidance can bring hope to an endangered world. Although attempts have been made to copy the work, efforts to do so fail to capture ...', 'equipped'),
    ('Item: Book of Vile Darkness', '[Artifact] The contents of this foul manuscript are the meat and drink of the wicked. It contains knowledge so horrid that to even glimpse the scrawled pages invites doom. Most believe the lich-god Vecna authored the Book of Vile Darkness. He recorded in its pages every horrid idea, every corrupt thought, and every example of foul magic he came across or devised.', 'equipped'),
    ('Item: Boots of Elvenkind', '[Uncommon] While you wear these boots, your steps make no sound, regardless of the surface you are moving across. You also have Advantage on Dexterity (Stealth) checks.', 'equipped'),
    ('Item: Boots of False Tracks', '[Common] While wearing these boots, you can have them leave tracks like those of any kind of Humanoid of your size.', 'equipped'),
    ('Item: Boots of Levitation', '[Rare] While you wear these boots, you can cast Levitate on yourself.', 'equipped'),
    ('Item: Boots of Speed', '[Rare] While you wear these boots, you can take a Bonus Action to click the boots'' heels together. If you do, the boots double your Speed, and any creature that makes an Opportunity Attack against you has Disadvantage on the attack roll. If you click your heels together again, you end the effect. When you''ve used the boots'' property for a total of 10 minutes, the magic ceases to function for you until you finish a Long Rest.', 'equipped'),
    ('Item: Boots of Striding and Springing', '[Uncommon] While you wear these boots, your Speed becomes 30 feet unless your Speed is higher, and your Speed isn''t reduced by you carrying weight in excess of your carrying capacity or wearing Heavy Armor. Once on each of your turns, you can jump up to 30 feet by spending only 10 feet of movement.', 'equipped'),
    ('Item: Boots of the Winterlands', '[Uncommon] These furred boots are snug and feel warm. While wearing them, you gain the following benefits. You have Resistance to Cold damage and can tolerate temperatures of 0 degrees Fahrenheit or lower without any additional protection.', 'equipped'),
    ('Item: Bowl of Commanding Water Elementals', '[Rare] While this bowl is filled with water and you are within 5 feet of it, you can take a Magic action to summon a Water Elemental. The elemental appears in an unoccupied space as close to the bowl as possible, understands your languages, obeys your commands, and takes its turn immediately after you on your Initiative count. The elemental disappears after 1 hour, when it dies, or when you dismiss it as a Bonus Action. The bowl can''t be used this way again until the next dawn. The bowl is about 1 foot in diameter and half as deep. It holds about 3 gallons.', 'equipped'),
    ('Item: Bracers of Archery', '[Uncommon] While wearing these bracers, you have proficiency with the Longbow and Shortbow, and you gain a +2 bonus to damage rolls made with such weapons.', 'equipped'),
    ('Item: Bracers of Defense', '[Rare] While wearing these bracers, you gain a +2 bonus to Armor Class if you are wearing no armor and using no Shield.', 'equipped'),
    ('Item: Brass Dragon Scale Mail', '[Very Rare] Dragon Scale Mail is made of the scales of one kind of dragon. Sometimes dragons collect their cast-off scales and gift them. Other times, hunters carefully preserve the hide of a dead dragon. In either case, Dragon Scale Mail is highly valued. While wearing this armor, you gain a +1 bonus to Armor Class, you have Advantage on saving throws against the breath weapons of Dragons, and you have Resistance to Fire damage.', 'equipped'),
    ('Item: Brazier of Commanding Fire Elementals', '[Rare] While you are within 5 feet of this brazier, you can take a Magic action to summon a Fire Elemental. The elemental appears in an unoccupied space as close to the brazier as possible, understands your languages, obeys your commands, and takes its turn immediately after you on your Initiative count. The elemental disappears after 1 hour, when it dies, or when you dismiss it as a Bonus Action. The brazier can''t be used this way again until the next dawn.', 'equipped'),
    ('Item: Bronze Dragon Scale Mail', '[Very Rare] Dragon Scale Mail is made of the scales of one kind of dragon. Sometimes dragons collect their cast-off scales and gift them. Other times, hunters carefully preserve the hide of a dead dragon. In either case, Dragon Scale Mail is highly valued. While wearing this armor, you gain a +1 bonus to Armor Class, you have Advantage on saving throws against the breath weapons of Dragons, and you have Resistance to Lightning damage.', 'equipped'),
    ('Item: Brooch of Shielding', '[Uncommon] While wearing this brooch, you have Resistance to Force damage, and you have Immunity to damage from the Magic Missile spell.', 'equipped'),
    ('Item: Broom of Flying', '[Uncommon] This wooden broom functions like a mundane broom until you stand astride it and take a Magic action to make it hover beneath you, at which time it can be ridden in the air. It has a Fly Speed of 50 feet. It can carry up to 400 pounds, but its Fly Speed becomes 30 feet while carrying over 200 pounds. The broom stops hovering when you land or when you''re no longer riding it. As a Magic action, you can send the broom to travel alone to a destination within 1 mile of you if you name the location and are familiar with it. The broom comes back to you when you take a Magic action and us...', 'equipped'),
    ('Item: Candle of Invocation', '[Very Rare] This candle''s magic is activated when the candle is lit, which requires a Magic action. After burning for 4 hours, the candle is destroyed. You can snuff it out early for use at a later time. Deduct the time it burned in increments of 1 minute from its total burn time. While lit, the candle sheds Dim Light in a 30-foot radius. While you are within that light, you have Advantage on D20 Tests. In addition, a Cleric or Druid in the light can cast level 1 spells they have prepared without expending spell slots.', 'equipped'),
    ('Item: Candle of the Deep', '[Common] The flame of this candle isn''t extinguished when immersed in water. It gives off light and heat like a normal candle.', 'equipped'),
    ('Item: Cap of Water Breathing', '[Uncommon] While wearing this cap underwater, you can take a Magic action to create a bubble of air around your head. This bubble allows you to breathe normally underwater. This bubble stays with you until the cap is removed or you are no longer underwater.', 'equipped'),
    ('Item: Cape of the Mountebank', '[Rare] This cape smells faintly of brimstone. While wearing it, you can use it to cast Dimension Door as a Magic action. This property can''t be used again until the next dawn. When you teleport with that spell, you leave behind a cloud of smoke. The space you left is Lightly Obscured by that smoke until the end of your next turn.', 'equipped'),
    ('Item: Carpet of Flying', '[Very Rare] You can make this carpet hover and fly by taking a Magic action and using the carpet''s command word. It moves according to your directions if you are within 30 feet of it. Four sizes of Carpet of Flying exist. The DM chooses the size of a given carpet or determines it randomly by rolling on the following table. A carpet can carry up to twice the weight shown on the table, but its Fly Speed is halved if it carries more than its normal capacity.', 'equipped'),
    ('Item: Carpet of Flying, 3 ft. × 5 ft.', '[Very Rare] You can make this carpet hover and fly by taking a Magic action and using the carpet''s command word. It moves according to your directions if you are within 30 feet of it. A 3 ft. × 5 ft. carpet can carry up to 200 lb. at a fly speed of 80 feet. A carpet can carry up to twice the weight shown on the table, but its Fly Speed is halved if it carries more than its normal capacity.', 'equipped'),
    ('Item: Carpet of Flying, 4 ft. × 6 ft.', '[Very Rare] You can make this carpet hover and fly by taking a Magic action and using the carpet''s command word. It moves according to your directions if you are within 30 feet of it. A 4 ft. × 6 ft. carpet can carry up to 400 lb. at a fly speed of 60 feet. A carpet can carry up to twice the weight shown on the table, but its Fly Speed is halved if it carries more than its normal capacity.', 'equipped'),
    ('Item: Carpet of Flying, 5 ft. × 7 ft.', '[Very Rare] You can make this carpet hover and fly by taking a Magic action and using the carpet''s command word. It moves according to your directions if you are within 30 feet of it. A 5 ft. × 7 ft. carpet can carry up to 600 lb. at a fly speed of 40 feet. A carpet can carry up to twice the weight shown on the table, but its Fly Speed is halved if it carries more than its normal capacity.', 'equipped'),
    ('Item: Carpet of Flying, 6 ft. × 9 ft.', '[Very Rare] You can make this carpet hover and fly by taking a Magic action and using the carpet''s command word. It moves according to your directions if you are within 30 feet of it. A 6 ft. × 9 ft. carpet can carry up to 800 lb. at a fly speed of 30 feet. A carpet can carry up to twice the weight shown on the table, but its Fly Speed is halved if it carries more than its normal capacity.', 'equipped'),
    ('Item: Cast-Off Armor', '[Common] You can doff this armor as a Magic action.', 'equipped'),
    ('Item: Cauldron of Rebirth', '[Very Rare] This Tiny pot bears relief scenes of heroes on its cast-iron sides. You can use the cauldron as a Spellcasting Focus for your spells, and it functions as a suitable component for the Scrying spell.', 'equipped'),
    ('Item: Censer of Controlling Air Elementals', '[Rare] While gently swinging this censer, you can take a Magic action to summon an Air Elemental. The elemental appears in an unoccupied space as close to the censer as possible, understands your languages, obeys your commands, and takes its turn immediately after you on your Initiative count. The elemental disappears after 1 hour, when it dies, or when you dismiss it as a Bonus Action. The censer can''t be used this way again until the next dawn.', 'equipped'),
    ('Item: Charlatan''s Die', '[Common] Whenever you roll this six-sided die, you can control which number it rolls.', 'equipped'),
    ('Item: Chime of Opening', '[Rare] This hollow metal tube measures about 1 foot long and weighs 1 pound. As a Magic action, you can strike the chime to cast Knock. The spell''s customary knocking sound is replaced by the clear, ringing tone of the chime, which is audible out to 300 feet. The chime can be used 10 times. After the tenth time, it cracks and becomes useless.', 'equipped'),
    ('Item: Circlet of Blasting', '[Uncommon] While wearing this circlet, you can cast Scorching Ray with it (+5 to hit). The circlet can''t cast this spell again until the next dawn.', 'equipped'),
    ('Item: Cloak of Arachnida', '[Very Rare] This fine garment is made of black silk interwoven with faint, silvery threads. While wearing it, you gain the following benefits. You have Resistance to Poison damage.', 'equipped'),
    ('Item: Cloak of Billowing', '[Common] While wearing this cloak, you can take a Bonus Action to make it billow dramatically for 1 minute.', 'equipped'),
    ('Item: Cloak of Displacement', '[Rare] While you wear this cloak, it magically projects an illusion that makes you appear to be standing in a place near your actual location, causing any creature to have Disadvantage on attack rolls against you. If you take damage, the property ceases to function until the start of your next turn. This property is suppressed while your Speed is 0.', 'equipped'),
    ('Item: Cloak of Elvenkind', '[Uncommon] While you wear this cloak, Wisdom (Perception) checks made to perceive you have Disadvantage, and you have Advantage on Dexterity (Stealth) checks.', 'equipped'),
    ('Item: Cloak of Invisibility', '[Legendary] This cloak has 3 charges and regains 1d3 expended charges daily at dawn. While wearing the cloak, you can take a Magic action to pull its hood over your head and expend 1 charge to give yourself the Invisible condition for 1 hour. The effect ends early if you pull the hood down (no action required) or cease wearing the hood.', 'equipped'),
    ('Item: Cloak of Many Fashions', '[Common] While wearing this cloak, you can take a Bonus Action to change the style, color, and apparent quality of the garment. The cloak''s weight doesn''t change. Regardless of its appearance, the cloak can''t be anything but a cloak. Although it can duplicate the appearance of other magic cloaks, it doesn''t gain their magical properties.', 'equipped'),
    ('Item: Cloak of Protection', '[Uncommon] You gain a +1 bonus to Armor Class and saving throws while you wear this cloak.', 'equipped'),
    ('Item: Cloak of the Bat', '[Rare] While wearing this cloak, you have Advantage on Dexterity (Stealth) checks. In an area of Dim Light or Darkness, you can grip the edges of the cloak and use it to gain a Fly Speed of 40 feet. If you ever fail to grip the cloak''s edges while flying in this way, or if you are no longer in Dim Light or Darkness, you lose this Fly Speed. While wearing the cloak in an area of Dim Light or Darkness, you can cast Polymorph on yourself, shape-shifting into a Bat. While in that form, you retain your Intelligence, Wisdom, and Charisma scores. The cloak can''t be used this way again until the ne...', 'equipped'),
    ('Item: Cloak of the Manta Ray', '[Uncommon] While wearing this cloak, you can breathe underwater, and you have a Swim Speed of 60 feet.', 'equipped'),
    ('Item: Clockwork Amulet', '[Common] This copper amulet contains tiny interlocking gears and is powered by magic from Mechanus, a plane of clockwork predictability. Faint ticking and whirring noises emanate from within. When you make an attack roll while wearing the amulet, you can forgo rolling the d20 to get a 10 on the die. Once used, this property can''t be used again until the next dawn.', 'equipped'),
    ('Item: Clothes of Mending', '[Common] This elegant outfit magically mends itself to counteract daily wear and tear. Pieces of the outfit that are destroyed can''t be repaired in this way.', 'equipped'),
    ('Item: Copper Dragon Scale Mail', '[Very Rare] Dragon Scale Mail is made of the scales of one kind of dragon. Sometimes dragons collect their cast-off scales and gift them. Other times, hunters carefully preserve the hide of a dead dragon. In either case, Dragon Scale Mail is highly valued. While wearing this armor, you gain a +1 bonus to Armor Class, you have Advantage on saving throws against the breath weapons of Dragons, and you have Resistance to Acid damage.', 'equipped'),
    ('Item: Crystal Ball', '[Very Rare] The typical crystal ball, a very rare item, is about 6 inches in diameter. While touching it, you can cast the Scrying spell (save DC 17) with it.', 'equipped'),
    ('Item: Crystal Ball of Mind Reading', '[Legendary] While touching this crystal orb, you can cast Scrying (save DC 17) with it. In addition, you can cast Detect Thoughts (save DC 17) targeting creatures you can see within 30 feet of the spell''s sensor. You don''t need to concentrate on this Detect Thoughts spell to maintain it during its duration, but it ends if the Scrying spell ends.', 'equipped'),
    ('Item: Crystal Ball of Telepathy', '[Legendary] While touching this crystal orb, you can cast Scrying (save DC 17) with it. In addition, you can communicate telepathically with creatures you can see within 30 feet of the spell''s sensor. You can also cast Suggestion (save DC 17) through the sensor on one of those creatures. You don''t need to concentrate on this Suggestion to maintain it during its duration, but it ends if Scrying ends. You can''t cast Suggestion in this way again until the next dawn.', 'equipped'),
    ('Item: Crystal Ball of True Seeing', '[Legendary] While touching this crystal orb, you can cast Scrying (save DC 17) with it. In addition, you have Truesight with a range of 120 feet centered on the spell''s sensor.', 'equipped'),
    ('Item: Cube of Force', '[Rare] This cube is about an inch across. Each face has a distinct marking on it. You can press one of those faces, expend the number of charges required for it, and thereby cast the spell associated with it (save DC 17), as shown in the Cube of Force Faces table. The cube starts with 10 charges, and it regains 1d6 expended charges daily at dawn.', 'equipped'),
    ('Item: Cube of Summoning', '[Rare] This Tiny cube looks like a jack-in-the-box. When you wind its crank as a Magic action, a merry tune emits from the box, the lid pops open, a creature appears in the nearest unoccupied space, and the lid closes. The lid can''t otherwise be opened. Roll on the Cube of Summoning table to determine which spell the cube casts to summon the creature. The spell is cast at level 5 (save DC 17, +9 attack bonus) and doesn''t require Concentration, but you otherwise function as the spell''s caster.', 'equipped'),
    ('Item: Cubic Gate', '[Legendary] This cube is 3 inches across and radiates palpable magical energy. The six sides of the cube are each keyed to a different plane of existence, one of which is the Material Plane. The other sides are linked to planes determined by the DM. The cube has 3 charges and regains 1d3 expended charges daily at dawn. As a Magic action, you can expend 1 of the cube''s charges to cast one of the following spells using the cube.', 'equipped'),
    ('Item: Daern''s Instant Fortress', '[Rare] As a Magic action, you can place this 1-inch adamantine statuette on the ground and, using a command word, cause it to grow rapidly into a square adamantine tower. Repeating the command word causes the tower to revert to statuette form, which works only if the tower is empty. Each creature in the area where the tower appears is pushed to an unoccupied space outside but next to the tower. Objects in the area that aren''t being worn or carried are also pushed clear of the tower. The tower is 20 feet on a side and 30 feet high, with arrow slits on all sides and a battlement atop it. Its ...', 'equipped'),
    ('Item: Dagger of Venom', '[Rare] You gain a +1 bonus to attack rolls and damage rolls made with this magic weapon. You can take a Bonus Action to magically coat the blade with poison. The poison remains for 1 minute or until an attack using this weapon hits a creature. That creature must succeed on a DC 15 Constitution saving throw or take 2d10 Poison damage and have the Poisoned condition for 1 minute. The weapon can''t be used this way again until the next dawn.', 'equipped'),
    ('Item: Dancing Sword', '[Very Rare] You can take a Bonus Action to toss this magic weapon into the air. When you do so, the weapon begins to hover, flies up to 30 feet, and attacks one creature of your choice within 5 feet of itself. The weapon uses your attack roll and adds your ability modifier to damage rolls. While the weapon hovers, you can take a Bonus Action to cause it to fly up to 30 feet to another spot within 30 feet of you. As part of the same Bonus Action, you can cause the weapon to attack one creature within 5 feet of the weapon.', 'equipped'),
    ('Item: Dark Shard Amulet', '[Common] This amulet is fashioned from a shard of resilient material originating from an otherworldly realm. While you are wearing it, you gain the following benefits. You can use the amulet as a Spellcasting Focus for your Warlock spells.', 'equipped'),
    ('Item: Decanter of Endless Water', '[Uncommon] This stoppered flask sloshes when shaken, as if it contains water. The decanter weighs 2 pounds. You can take a Magic action to remove the stopper and issue one of three command words, whereupon an amount of fresh water or salt water (your choice) pours out of the flask. The water stops pouring out at the start of your next turn. Choose from the following command words:', 'equipped'),
    ('Item: Deck of Illusions', '[Uncommon] This box contains a set of cards. A full deck has 34 cards: 32 depicting specific creatures and two with a mirrored surface. A deck found as treasure is usually missing 1d20 - 1 cards. The magic of the deck functions only if its cards are drawn at random. You can take a Magic action to draw a card at random from the deck and throw it to the ground at a point within 30 feet of yourself. An illusion of a creature, determined by rolling on the Deck of Illusions table, forms over the thrown card and remains until dispelled. The illusory creature created by the card looks and behaves ...', 'equipped'),
    ('Item: Deck of Many Things', '[Legendary] Usually found in a box or pouch, this deck contains a number of cards made of ivory or vellum. Most (75 percent) of these decks have thirteen cards, but some have twenty-two. Use the appropriate column of the Deck of Many Things table when randomly determining cards drawn from the deck. Before you draw a card, you must declare how many cards you intend to draw and then draw them randomly. Any cards drawn in excess of this number have no effect. Otherwise, as soon as you draw a card from the deck, its magic takes effect. You must draw each card no more than 1 hour after the previ...', 'equipped'),
    ('Item: Defender', '[Legendary] You gain a +3 bonus to attack rolls and damage rolls made with this magic weapon. The first time you attack with the weapon on each of your turns, you can transfer some or all of the weapon''s bonus to your Armor Class. For example, you could reduce the bonus to your attack rolls and damage rolls to +1 and gain a +2 bonus to Armor Class. The adjusted bonuses remain in effect until the start of your next turn, although you must hold the weapon to gain a bonus to AC from it.', 'equipped'),
    ('Item: Demon Armor', '[Very Rare] While wearing this armor, you gain a +1 bonus to Armor Class, and you know Abyssal. In addition, the armor''s clawed gauntlets allow your Unarmed Strikes to deal 1d8 Slashing damage instead of the usual Bludgeoning damage, and you gain a +1 bonus to the attack and damage rolls of your Unarmed Strikes. Once you don this cursed armor, you can''t doff it unless you are targeted by a Remove Curse spell or similar magic. While wearing the armor, you have Disadvantage on attack rolls against demons and on saving throws against their spells and special abilities.', 'equipped'),
    ('Item: Demonomicon of Iggwilv', '[Artifact] This treatise, composed by Iggwilv the archmage, documents the Abyss''s layers and inhabitants and is widely regarded as the most thorough and blasphemous tome of demonology in the multiverse. The tome recounts both the oldest and most current profanities of the Abyss and demons. Demons have attempted to censor the text, and while sections have been ripped from the book''s spine, the general chapters remain, ever revealing demonic secrets. Caged behind lines of script roils a secret piece of the Abyss itself, which keeps the book up-to-date, no matter how many pages are removed, an...', 'equipped'),
    ('Item: Dimensional Shackles', '[Rare] You can take a Utilize action to place these shackles on a creature that has the Incapacitated condition. The shackles adjust to fit a creature of Small to Large size. The shackles prevent a creature bound by them from using any method of extradimensional movement, including teleportation or travel to a different plane of existence. They don''t prevent the creature from passing through an interdimensional portal. You and any creature you designate when you use the shackles can take a Utilize action to remove them. Once every 30 days, the bound creature can make a DC 30 Strength (Athle...', 'equipped'),
    ('Item: Dragon Scale Mail', '[Very Rare] Disadvantage on Stealth (Dexterity) checks.', 'equipped'),
    ('Item: Dragon Slayer', '[Rare] You gain a +1 bonus to attack rolls and damage rolls made with this magic weapon. The weapon deals an extra 3d6 damage of the weapon''s type if the target is a Dragon.', 'equipped'),
    ('Item: Dread Helm', '[Common] While you''re wearing this fearsome steel helm, your eyes glow red and the rest of your face is hidden in shadow.', 'equipped'),
    ('Item: Driftglobe', '[Uncommon] This small sphere of thick glass weighs 1 pound. If you are within 60 feet of it, you can command it to emanate light equivalent to that of the Light or Daylight spell (your choice). Once used, the Daylight effect can''t be used again until the next dawn. You can issue another command as a Magic action to make the illuminated globe rise into the air and float no more than 5 feet off the ground. The globe hovers in this way until you or another creature grasps it. If you move more than 60 feet from the hovering globe, it follows you until it is within 60 feet of you. It takes the s...', 'equipped'),
    ('Item: Dust of Disappearance', '[Uncommon] This powder resembles fine sand. There is enough of it for one use. When you take a Utilize action to throw the dust into the air, you and each creature and object within a 10-foot Emanation originating from you have the Invisible condition for 2d4 minutes. The duration is the same for all subjects, and the dust is consumed when its magic takes effect. Immediately after an affected creature makes an attack roll, deals damage, or casts a spell, the Invisible condition ends for that creature.', 'equipped'),
    ('Item: Dust of Dryness', '[Uncommon] This small packet contains 1d6 + 4 pinches of dust. As a Utilize action, you can sprinkle a pinch of the dust over water, turning up to a 15-foot Cube of water into one marble-sized pellet, which floats or rests near where the dust was sprinkled. The pellet''s weight is negligible. A creature can take a Utilize action to smash the pellet against a hard surface, causing the pellet to shatter and release the water the dust absorbed. Doing so destroys the pellet and ends its magic. As a Utilize action, you can sprinkle a pinch of the dust on an Elemental within 5 feet of yourself tha...', 'equipped'),
    ('Item: Dust of Sneezing and Choking', '[Uncommon] Found in a small container, this powder resembles Dust of Disappearance, and Identify reveals it to be such. There is enough of it for one use. As a Utilize action, you can throw the dust into the air, forcing yourself and every creature in a 30-foot Emanation originating from you to make a DC 15 Constitution saving throw. Constructs, Elementals, Oozes, Plants, and Undead succeed on the save automatically.', 'equipped'),
    ('Item: Dwarven Plate', '[Very Rare] While wearing this armor, you gain a +2 bonus to Armor Class. In addition, if an effect moves you against your will along the ground, you can take a Reaction to reduce the distance you are moved by up to 10 feet.', 'equipped'),
    ('Item: Dwarven Thrower', '[Very Rare] You gain a +3 bonus to attack rolls and damage rolls made with this magic weapon. It has Thrown with a normal range of 20 feet and a long range of 60 feet. When you hit with a ranged attack using this weapon, it deals an extra 1d8 Force damage, or an extra 2d8 Force damage if the target is a Giant. Immediately after hitting or missing, the weapon flies back to your hand. If a weapon has the Thrown property, you can throw the weapon to make a ranged attack, and you can draw that weapon as part of the attack. If the weapon is a Melee weapon, use the same ability modifier for the a...', 'equipped'),
    ('Item: Ear Horn of Hearing', '[Common] While held up to your ear, this horn suppresses the effects of the Deafened condition on you.', 'equipped'),
    ('Item: Efreeti Bottle', '[Very Rare] When you take a Magic action to remove the stopper of this painted brass bottle, a cloud of thick smoke flows out of it. At the end of your turn, the smoke disappears with a flash of harmless fire, and an Efreeti appears in an unoccupied space within 30 feet of you. The first time the bottle is opened, the DM rolls on the following table to determine what happens.', 'equipped'),
    ('Item: Efreeti Chain', '[Legendary] While wearing this armor, you gain a +3 bonus to Armor Class, you have Immunity to Fire damage, and you know Primordial. In addition, you can stand on and move across molten rock as if it were solid ground.', 'equipped'),
    ('Item: Elemental Gem', '[Uncommon] Wondrous Item, Uncommon', 'equipped'),
    ('Item: Elemental Gem, Blue Sapphire', '[Uncommon] This gem contains a mote of elemental energy. When you take a Utilize action to break the gem, an Air Elemental is summoned, and the gem ceases to be magical. The elemental appears in an unoccupied space as close to the broken gem as possible, understands your languages, obeys your commands, and takes its turn immediately after you on your Initiative count. The elemental disappears after 1 hour, when it dies, or when you dismiss it as a Bonus Action.', 'equipped'),
    ('Item: Elemental Gem, Emerald', '[Uncommon] This gem contains a mote of elemental energy. When you take a Utilize action to break the gem, a Water Elemental is summoned, and the gem ceases to be magical. The elemental appears in an unoccupied space as close to the broken gem as possible, understands your languages, obeys your commands, and takes its turn immediately after you on your Initiative count. The elemental disappears after 1 hour, when it dies, or when you dismiss it as a Bonus Action.', 'equipped'),
    ('Item: Elemental Gem, Red Corundum', '[Uncommon] This gem contains a mote of elemental energy. When you take a Utilize action to break the gem, a Fire Elemental is summoned, and the gem ceases to be magical. The elemental appears in an unoccupied space as close to the broken gem as possible, understands your languages, obeys your commands, and takes its turn immediately after you on your Initiative count. The elemental disappears after 1 hour, when it dies, or when you dismiss it as a Bonus Action.', 'equipped'),
    ('Item: Elemental Gem, Yellow Diamond', '[Uncommon] This gem contains a mote of elemental energy. When you take a Utilize action to break the gem, an Earth Elemental is summoned, and the gem ceases to be magical. The elemental appears in an unoccupied space as close to the broken gem as possible, understands your languages, obeys your commands, and takes its turn immediately after you on your Initiative count. The elemental disappears after 1 hour, when it dies, or when you dismiss it as a Bonus Action.', 'equipped'),
    ('Item: Elixir of Health', '[Rare] When you drink this potion, you are cured of all magical contagions. In addition, the following conditions end on you: Blinded, Deafened, Paralyzed, and Poisoned. The clear, red liquid has tiny bubbles of light in it.', 'equipped'),
    ('Item: Elven Chain', '[Rare] You gain a +1 bonus to Armor Class while you wear this armor. You are considered trained with this armor even if you lack training with Medium or Heavy armor.', 'equipped'),
    ('Item: Enduring Spellbook', '[Common] This spellbook, along with anything written on its pages, can''t be damaged by fire or water. In addition, the spellbook doesn''t deteriorate with age.', 'equipped'),
    ('Item: Energy Bow', '[Very Rare] You gain a +1 bonus to attack rolls and damage rolls made with this magic weapon, which has no string. Each time you pull your arm back in a firing motion, a magical arrow made of golden energy appears nocked and ready to fire. An arrow produced by this weapon deals Force damage instead of Piercing damage on a hit, and it disappears after it hits or misses its target. Until it disappears, the arrow emits Bright Light in a 20-foot radius and Dim Light for an additional 20 feet. This weapon has the following additional properties.', 'equipped'),
    ('Item: Enspelled Armor', 'Generic Variant (Requires Attunement)', 'equipped'),
    ('Item: Enspelled Armor (Cantrip)', '[Uncommon] Bound into this armor is a cantrip. The cantrip is determined when the armor is created and must belong to the Abjuration or Illusion school of magic. The armor has 6 charges and regains 1d6 expended charges daily at dawn. While wearing the armor, you can expend 1 charge to cast its spell. The spell''s saving throw DC is 13, and its attack bonus is +5.', 'equipped'),
    ('Item: Enspelled Armor (Level 1)', '[Uncommon] Bound into this armor is a level 1 spell. The spell is determined when the armor is created and must belong to the Abjuration or Illusion school of magic. The armor has 6 charges and regains 1d6 expended charges daily at dawn. While wearing the armor, you can expend 1 charge to cast its spell. The spell''s saving throw DC is 13, and its attack bonus is +5.', 'equipped'),
    ('Item: Enspelled Armor (Level 2)', '[Rare] Bound into this armor is a level 2 spell. The spell is determined when the armor is created and must belong to the Abjuration or Illusion school of magic. The armor has 6 charges and regains 1d6 expended charges daily at dawn. While wearing the armor, you can expend 1 charge to cast its spell. The spell''s saving throw DC is 13, and its attack bonus is +5.', 'equipped'),
    ('Item: Enspelled Armor (Level 3)', '[Rare] Bound into this armor is a level 3 spell. The spell is determined when the armor is created and must belong to the Abjuration or Illusion school of magic. The armor has 6 charges and regains 1d6 expended charges daily at dawn. While wearing the armor, you can expend 1 charge to cast its spell. The spell''s saving throw DC is 15, and its attack bonus is +7.', 'equipped'),
    ('Item: Enspelled Armor (Level 4)', '[Very Rare] Bound into this armor is a level 4 spell. The spell is determined when the armor is created and must belong to the Abjuration or Illusion school of magic. The armor has 6 charges and regains 1d6 expended charges daily at dawn. While wearing the armor, you can expend 1 charge to cast its spell. The spell''s saving throw DC is 15, and its attack bonus is +7.', 'equipped'),
    ('Item: Enspelled Armor (Level 5)', '[Very Rare] Bound into this armor is a level 5 spell. The spell is determined when the armor is created and must belong to the Abjuration or Illusion school of magic. The armor has 6 charges and regains 1d6 expended charges daily at dawn. While wearing the armor, you can expend 1 charge to cast its spell. The spell''s saving throw DC is 17, and its attack bonus is +9.', 'equipped'),
    ('Item: Enspelled Armor (Level 6)', '[Legendary] Bound into this armor is a level 6 spell. The spell is determined when the armor is created and must belong to the Abjuration or Illusion school of magic. The armor has 6 charges and regains 1d6 expended charges daily at dawn. While wearing the armor, you can expend 1 charge to cast its spell. The spell''s saving throw DC is 17, and its attack bonus is +9.', 'equipped'),
    ('Item: Enspelled Armor (Level 7)', '[Legendary] Bound into this armor is a level 7 spell. The spell is determined when the armor is created and must belong to the Abjuration or Illusion school of magic. The armor has 6 charges and regains 1d6 expended charges daily at dawn. While wearing the armor, you can expend 1 charge to cast its spell. The spell''s saving throw DC is 18, and its attack bonus is +10.', 'equipped'),
    ('Item: Enspelled Armor (Level 8)', '[Legendary] Bound into this armor is a level 8 spell. The spell is determined when the armor is created and must belong to the Abjuration or Illusion school of magic. The armor has 6 charges and regains 1d6 expended charges daily at dawn. While wearing the armor, you can expend 1 charge to cast its spell. The spell''s saving throw DC is 18, and its attack bonus is +10.', 'equipped'),
    ('Item: Enspelled Staff', 'A Versatile weapon can be used with one or two hands. A damage value in parentheses appears with the property. The weapon deals that damage when used with two hands to make a melee attack.', 'equipped'),
    ('Item: Enspelled Staff (Cantrip)', '[Uncommon] Bound into this staff is a cantrip. The cantrip is determined when the staff is created and can be of any school of magic. The staff has 6 charges and regains 1d6 expended charges daily at dawn. While holding the staff, you can expend 1 charge to cast its spell. If you expend the staff''s last charge, roll 1d20. On a 1, the staff loses its properties and becomes a nonmagical Quarterstaff. The spell''s saving throw DC is 13, and its attack bonus is +5.', 'equipped'),
    ('Item: Enspelled Staff (Level 1)', '[Uncommon] Bound into this staff is a level 1 spell. The spell is determined when the staff is created and can be of any school of magic. The staff has 6 charges and regains 1d6 expended charges daily at dawn. While holding the staff, you can expend 1 charge to cast its spell. If you expend the staff''s last charge, roll 1d20. On a 1, the staff loses its properties and becomes a nonmagical Quarterstaff. The spell''s saving throw DC is 13, and its attack bonus is +5.', 'equipped'),
